diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..08f7a64b7102 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7885,6 +7885,7 @@ static Instruction *foldFCmpFNegCommonOp(FCmpInst &I) {
   return new FCmpInst(Pred, Op0, Zero, "", &I);
 }

+
 Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   bool Changed = false;

@@ -7907,20 +7908,21 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   assert(OpType == Op1->getType() && "fcmp with different-typed operands?");
   if (Op0 == Op1) {
     switch (Pred) {
-      default: break;
-    case FCmpInst::FCMP_UNO:    // True if unordered: isnan(X) | isnan(Y)
-    case FCmpInst::FCMP_ULT:    // True if unordered or less than
-    case FCmpInst::FCMP_UGT:    // True if unordered or greater than
-    case FCmpInst::FCMP_UNE:    // True if unordered or not equal
+    default:
+      break;
+    case FCmpInst::FCMP_UNO: // True if unordered: isnan(X) | isnan(Y)
+    case FCmpInst::FCMP_ULT: // True if unordered or less than
+    case FCmpInst::FCMP_UGT: // True if unordered or greater than
+    case FCmpInst::FCMP_UNE: // True if unordered or not equal
       // Canonicalize these to be 'fcmp uno %X, 0.0'.
       I.setPredicate(FCmpInst::FCMP_UNO);
       I.setOperand(1, Constant::getNullValue(OpType));
       return &I;

-    case FCmpInst::FCMP_ORD:    // True if ordered (no nans)
-    case FCmpInst::FCMP_OEQ:    // True if ordered and equal
-    case FCmpInst::FCMP_OGE:    // True if ordered and greater than or equal
-    case FCmpInst::FCMP_OLE:    // True if ordered and less than or equal
+    case FCmpInst::FCMP_ORD: // True if ordered (no nans)
+    case FCmpInst::FCMP_OEQ: // True if ordered and equal
+    case FCmpInst::FCMP_OGE: // True if ordered and greater than or equal
+    case FCmpInst::FCMP_OLE: // True if ordered and less than or equal
       // Canonicalize these to be 'fcmp ord %X, 0.0'.
       I.setPredicate(FCmpInst::FCMP_ORD);
       I.setOperand(1, Constant::getNullValue(OpType));
@@ -8040,6 +8042,62 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // Fold compares against zero through a select-based fabs idiom:
+  //   %c = fcmp oge X, 0.0
+  //   %n = fneg X
+  //   %a = select i1 %c, X, %n
+  //   fcmp eq/ne %a, 0.0 --> fcmp eq/ne X, 0.0
+  if (match(Op1, m_PosZeroFP())) {
+    auto MatchAbsSelect = [&](Value *V, Value *&Src) -> bool {
+      auto *SI = dyn_cast<SelectInst>(V);
+      if (!SI)
+        return false;
+
+      auto *Cmp = dyn_cast<FCmpInst>(SI->getCondition());
+      if (!Cmp)
+        return false;
+
+      Value *TrueV = SI->getTrueValue();
+      Value *FalseV = SI->getFalseValue();
+
+      Value *NegX;
+      const APFloat *CmpC;
+
+      // select (fcmp oge X, +/-0.0), X, (fneg X)
+      if (Cmp->getPredicate() == FCmpInst::FCMP_OGE &&
+          match(Cmp->getOperand(1), m_APFloat(CmpC)) && CmpC->isZero() &&
+          TrueV == Cmp->getOperand(0) && match(FalseV, m_FNeg(m_Value(NegX))) &&
+          NegX == Cmp->getOperand(0)) {
+        Src = NegX;
+        return true;
+      }
+
+      // select (fcmp ole +/-0.0, X), X, (fneg X)
+      if (Cmp->getPredicate() == FCmpInst::FCMP_OLE &&
+          match(Cmp->getOperand(0), m_APFloat(CmpC)) && CmpC->isZero() &&
+          TrueV == Cmp->getOperand(1) && match(FalseV, m_FNeg(m_Value(NegX))) &&
+          NegX == Cmp->getOperand(1)) {
+        Src = NegX;
+        return true;
+      }
+
+      return false;
+    };
+
+    Value *Src;
+    if (MatchAbsSelect(Op0, Src)) {
+      switch (Pred) {
+      default:
+        break;
+      case FCmpInst::FCMP_OEQ:
+      case FCmpInst::FCMP_UEQ:
+      case FCmpInst::FCMP_ONE:
+      case FCmpInst::FCMP_UNE:
+        return new FCmpInst(Pred, Src, ConstantFP::getZero(OpType), "", &I);
+      }
+    }
+  }
+
   // Handle fcmp with instruction LHS and constant RHS.
   Instruction *LHSI;
   Constant *RHSC;
@@ -8065,7 +8123,7 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
                   cast<LoadInst>(LHSI), GEP, GV, I))
             return Res;
       break;
-  }
+    }
   }

   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
@@ -8180,3 +8238,4 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {

   return Changed ? &I : nullptr;
 }
+

